@Override
public Gist create(final Iterable<String> files) throws IOException {
    this.storage.lock();
    final String number;
    try {
        number = Integer.toString(
            1 + this.storage.xml().xpath(
                String.format("%s/gist/id/text()", this.xpath())
            ).size()
        );
        final Directives dirs = new Directives().xpath(this.xpath())
            .add("gist")
            .add("id").set(number).up()
            .add("files");
        for (final String file : files) {
            dirs.add("file")
                .add("filename").set(file).up()
                .add("raw_content").up().up();
        }
        this.storage.apply(dirs);
    } finally {
        this.storage.unlock();
    }
    return this.get(number);
}

